def reorder_player_starter(row: dict) -> dict:
    """Place PlayerStarter immediately after BattleOrder when present."""
    if "PlayerStarter" not in row:
        return dict(row)

    reordered = {}

    for key, value in row.items():
        if key == "PlayerStarter":
            continue

        reordered[key] = value

        if key == "BattleOrder":
            reordered["PlayerStarter"] = row["PlayerStarter"]

    return reordered


def validate(rows: list[dict]) -> None:
    leon_rows = [row for row in rows if row.get("Trainer") == "Leon"]
    hop_rows = [row for row in rows if row.get("Trainer") == "Hop"]

    expected_leon = {
        "Grookey": 6,
        "Scorbunny": 6,
        "Sobble": 6,
    }

    leon_counts = Counter(
        row.get("PlayerStarter")
        for row in leon_rows
    )

    if leon_counts != expected_leon:
        raise ValueError(
            f"Leon validation failed: {dict(leon_counts)}"
        )

    hop_tagged = [
        row for row in hop_rows
        if row.get("PlayerStarter")
    ]
    hop_shared = [
        row for row in hop_rows
        if not row.get("PlayerStarter")
    ]

    expected_hop = {
        "Grookey": 10,
        "Scorbunny": 10,
        "Sobble": 10,
    }

    hop_counts = Counter(
        row.get("PlayerStarter")
        for row in hop_tagged
    )

    if hop_counts != expected_hop:
        raise ValueError(
            f"Hop validation failed: {dict(hop_counts)}"
        )

    if len(hop_shared) != 32:
        raise ValueError(
            f"Expected 32 shared Hop rows; found {len(hop_shared)}."
        )

    # Explicitly verify the exact row that exposed the problem.
    postwick_grookey = [
        row
        for row in hop_rows
        if (
            row.get("Battle") == "Postwick"
            and row.get("Pokemon") == "Grookey"
        )
    ]

    if len(postwick_grookey) != 1:
        raise ValueError(
            "Expected exactly one Hop/Postwick/Grookey row."
        )

    if postwick_grookey[0].get("PlayerStarter") != "Scorbunny":
        raise ValueError(
            "Hop's Postwick Grookey row is missing "
            'PlayerStarter: "Scorbunny".'
        )

    for row in leon_rows + hop_tagged:
        keys = list(row)

        if "PlayerStarter" not in row:
            raise ValueError(
                "Starter-dependent row is missing PlayerStarter: "
                f"{row.get('Trainer')} / {row.get('Battle')} / "
                f"{row.get('Pokemon')}"
            )

        if keys.index("PlayerStarter") != keys.index("BattleOrder") + 1:
            raise ValueError(
                "PlayerStarter is not immediately after BattleOrder: "
                f"{row.get('Trainer')} / {row.get('Battle')} / "
                f"{row.get('Pokemon')}"
            )


def main() -> None:
    if not OPPONENTS_PATH.exists():
        raise FileNotFoundError(
            f"Could not find {OPPONENTS_PATH}."
        )

    with OPPONENTS_PATH.open("r", encoding="utf-8") as file:
        current_rows = json.load(file)

    unaffected_rows = [
        row
        for row in current_rows
        if row.get("Trainer") not in {"Hop", "Leon"}
    ]

    updated_rows = [
        reorder_player_starter(row)
        for row in (
            unaffected_rows
            + HOP_ROWS
            + LEON_ROWS
        )
    ]

    validate(updated_rows)

    shutil.copy2(OPPONENTS_PATH, BACKUP_PATH)

    with OPPONENTS_PATH.open("w", encoding="utf-8") as file:
        json.dump(
            updated_rows,
            file,
            ensure_ascii=False,
            indent=2,
        )
        file.write("\n")

    print("Starter-dependent opponent data updated successfully.")
    print(f"Backup: {BACKUP_PATH}")
    print(f"Updated: {OPPONENTS_PATH}")
    print(f"Total rows: {len(updated_rows)}")
    print("Leon: 6 rows per starter")
    print("Hop: 32 shared rows + 10 starter rows per starter")
    print('Verified: Hop/Postwick/Grookey has PlayerStarter "Scorbunny".')


if __name__ == "__main__":
    main()